import{_ as o,o as a,c as i,ag as n}from"./chunks/framework.NIzFHKo_.js";const g=JSON.parse('{"title":"ADR-0006: Narrative and Knowledge Layer Consolidation","description":"","frontmatter":{"title":"ADR-0006: Narrative and Knowledge Layer Consolidation","status":"accepted ... ...","created_at":"2026-03-30","updated_at":"2026-03-30","author":"Antigravity ... ...","source_type":"manual ... ...","supersedes":"","id":"0006","short_code":"NARRATIVE_CONSOLIDATION ... ...","domain_prefix":"core ... ...","document_type":"adr ... ...","context_domain":"core ... ..."},"headers":[],"relativePath":"10_core/10_governance/50_decisions/adr-0006_narrative_and_knowledge_consolidation.md","filePath":"10_core/10_governance/50_decisions/adr-0006_narrative_and_knowledge_consolidation.md"}'),t={name:"10_core/10_governance/50_decisions/adr-0006_narrative_and_knowledge_consolidation.md"};function r(l,e,c,d,s,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-0006-narrative-and-knowledge-layer-consolidation" tabindex="-1">ADR-0006: Narrative and Knowledge Layer Consolidation <a class="header-anchor" href="#adr-0006-narrative-and-knowledge-layer-consolidation" aria-label="Permalink to &quot;ADR-0006: Narrative and Knowledge Layer Consolidation&quot;">​</a></h1><p><strong>Status:</strong> Accepted <strong>Date:</strong> 2026-03-30</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The QiOS / QiOne ecosystem has accumulated overlapping top-level product namespace terminology over time, leading to collisions and lack of clarity. Concepts like <code>QiHistory</code>, <code>QJournal</code>, <code>QsaysIt</code>, <code>Qistory</code>, <code>QiArchive</code>, <code>QiNote</code>, <code>QiNode</code>, and <code>QiObjects</code> have been used inconsistently. To formalize the QiOS ontology and comply with the Master Blueprint rules (one canonical home per concern, no silent duplication), we must officially define the canonical roles of these concepts and retire redundancies.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>We establish the following canonical merge map and definitions:</p><ul><li><strong>QiArchive</strong>: The exclusive canonical archival identity spine and raw file ingest layer.</li><li><strong>QiNote</strong>: The exclusive canonical knowledge and local-first markdown note layer.</li><li><strong>QiNode</strong>: The derived semantic and structural intelligence layer (never a canonical source of truth for records).</li><li><strong>QiHistory</strong>: The consolidated top-level narrative/history umbrella and chronological event log.</li></ul><p>The following terms are formally retired and stripped from the active ontology:</p><ul><li><strong>QJournal</strong> (Merged into <code>QiHistory</code>)</li><li><strong>Qistory</strong> (Merged into <code>QiHistory</code>)</li><li><strong>QsaysIt</strong> (Retired / Out of Scope for canonical ontology)</li><li><strong>QiObjects</strong> (Retired as a top-level functional namespace)</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Eliminates conceptual duplication and namespace collisions.</li><li>Reinforces the &quot;single domain rule&quot; by giving chronological events, knowledge, and archives explicitly unique, non-overlapping names.</li><li>Simplifies onboarding and architectural referencing.</li></ul><h3 id="negative-ripple-effects" tabindex="-1">Negative (Ripple Effects) <a class="header-anchor" href="#negative-ripple-effects" aria-label="Permalink to &quot;Negative (Ripple Effects)&quot;">​</a></h3><ul><li>Any existing code, scripts, or legacy <code>.legacy</code> folders using the retired terms might need renaming or archival, causing minor path update friction.</li><li>Users accustomed to the old nomenclature will need to adopt the canonical terms.</li></ul><h2 id="affected-documents" tabindex="-1">Affected Documents <a class="header-anchor" href="#affected-documents" aria-label="Permalink to &quot;Affected Documents&quot;">​</a></h2><ul><li><code>docs/02_architecture/index.md</code></li><li><code>docs/02_architecture/system_model.md</code></li><li><code>docs/appendices/changelog.md</code></li></ul>',16)])])}const p=o(t,[["render",r]]);export{g as __pageData,p as default};
